// HasSource applies the HasEdge predicate on the "source" edge.
func HasSource() predicate.UpstreamPriceChange {
	return predicate.UpstreamPriceChange(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.M2O, true, SourceTable, SourceColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasSourceWith applies the HasEdge predicate on the "source" edge with a given conditions (other predicates).
func HasSourceWith(preds ...predicate.UpstreamPriceSource) predicate.UpstreamPriceChange {
	return predicate.UpstreamPriceChange(func(s *sql.Selector) {
		step := newSourceStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.UpstreamPriceChange) predicate.UpstreamPriceChange {
	return predicate.UpstreamPriceChange(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.UpstreamPriceChange) predicate.UpstreamPriceChange {
	return predicate.UpstreamPriceChange(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.UpstreamPriceChange) predicate.UpstreamPriceChange {
	return predicate.UpstreamPriceChange(sql.NotPredicates(p))
}
